      answerCode={`public class Exercise03 {

    public static boolean isPrime(int n) {
        if (n <= 1) {
            return false;           // 1 及以下不是质数
        }
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) {
                return false;       // 找到因数，不是质数
