        } else if (score >= 60) {
            return "C";
        }
        // 缺少一个 return，请补全
    }

    public static void main(String[] args) {
        // 在这里补全代码
    }
}`}
      answerCode={`public class Exercise02 {

    public static String getLevel(int score) {
        if (score >= 90) {
            return "A";
        } else if (score >= 70) {
