    }
}`}
      answerCode={`public class Exercise03 {

    public static int getLast(int[] arr) {
        if (arr == null) {
            System.out.println("数组为 null");
            return -1;
        }
        if (arr.length == 0) {
            System.out.println("数组为空");
            return -1;
        }
