        // [5, 15]  — 5 到 15（共 11 个数，15-5+1=11）
        int d = r.nextInt(11) + 5;

        // [-5, 5]  — -5 到 5（共 11 个数，5-(-5)+1=11）
        int e = r.nextInt(11) - 5;

        System.out.println("[0,  9] : " + a);
