      answerCode={`public class Exercise01 {
    public static void main(String[] args) {
        // 圆面积
        double r = 7;
        double area = Math.PI * Math.pow(r, 2);
        System.out.printf("半径 %.0f 的圆面积 = %.2f%n", r, area);

        // 斜边（勾股定理）
