        animal.sound();
    }

    public static void main(String[] args) {
        // 写法1：先赋值给变量，再传入
        Animal dog = new Animal("小狗") {
            @Override
            public void sound() {
                System.out.println("汪汪汪！");
            }
        };
        makeAnimalSound(dog);

        // 写法2：直接作为参数传入（更简洁，最常见）
        makeAnimalSound(new Animal("小猫") {
            @Override
            public void sound() {
                System.out.println("喵喵喵！");
            }
