        schedule(new Worker() {
            @Override
            public void work() {
                System.out.println("程序员：敲代码、改 Bug、写文档");
            }

            @Override
            public void rest() {
                System.out.println("程序员：刷手机、喝咖啡、闭眼5分钟");
            }
        });

